const body = $json.body || $json;
if (!body.provider || !body.input) throw new Error('provider + input required');
if (!body.input.orderId) throw new Error('input.orderId required');
return [{ json: {
  correlationId: `inv-query-${Date.now()}-${Math.floor(Math.random()*1e6)}`,
  startedAt: new Date().toISOString(),
  provider: body.provider,
  input: body.input
}}];

const state = $('Stamp correlation').first().json;
const statusCode = Number($json.statusCode ?? 0);
const respBody = $json.body ?? $json;
// svc returns 400 + error.code:NOT_FOUND when no invoice for orderId; treat as 'found:false' not error.
const notFound = statusCode === 400 && respBody?.error?.code === 'NOT_FOUND';
const found = statusCode >= 200 && statusCode < 300;
const unsupported = statusCode === 400 && respBody?.error?.code === 'UNSUPPORTED';
return [{ json: {
  ...state,
  statusCode,
  found,
  notFound,
  unsupported,
  invoiceNumber: found ? respBody?.result?.invoiceNumber : null,
  status: found ? respBody?.result?.status : null,
  errorCode: respBody?.error?.code ?? null,
  appliedAt: new Date().toISOString()
} }];
